import React from "react";
import {
  User,
  Smartphone,
  History,
  LogOut,
  Bell,
  Shield,
  ChevronRight,
} from "lucide-react";

export default function ProfileScreen({ user, darkMode, onLogout, onHistory }) {
  const menuItems = [
    {
      icon: User,
      label: "Personal Information",
      color: darkMode ? "bg-emerald-700 text-emerald-100" : "bg-emerald-50 text-emerald-600",
    },
    { icon: Bell, label: "Notifications", color: darkMode ? "bg-blue-700 text-blue-100" : "bg-blue-50 text-blue-600" },
    {
      icon: Shield,
      label: "Security & Privacy",
      color: darkMode ? "bg-purple-700 text-purple-100" : "bg-purple-50 text-purple-600",
    },
    {
      icon: Smartphone,
      label: "Linked Devices",
      color: darkMode ? "bg-orange-700 text-orange-100" : "bg-orange-50 text-orange-600",
    },
    {
      icon: History,
      label: "Transactions History",
      color: darkMode ? "bg-gray-700 text-gray-100" : "bg-gray-100 text-gray-600",
      action: onHistory,
    },
  ];

  // Generate initials from user name
  const getInitials = (name) => {
    if (!name) return "U";
    const parts = name.trim().split(" ");
    if (parts.length === 1) return parts[0].charAt(0).toUpperCase();
    return (parts[0].charAt(0) + parts[1].charAt(0)).toUpperCase();
  };

  return (
    <div className={`p-6 pb-24 animate-in fade-in duration-300 ${darkMode ? "bg-gray-900 text-gray-100" : "bg-white text-gray-900"}`}>
      {/* Avatar and User Info */}
      <div className="flex flex-col items-center mb-10 pt-8">
        <div className="relative">
          <div className="w-28 h-28 bg-emerald-50 rounded-full flex items-center justify-center text-5xl border-4 border-white shadow-xl">
            {user?.avatar ? (
              <img src={user.avatar} alt="avatar" className="w-full h-full rounded-full" />
            ) : (
              getInitials(user?.name)
            )}
          </div>
          <div className="absolute bottom-1 right-1 w-8 h-8 bg-[#00875A] rounded-full border-4 border-white flex items-center justify-center">
            <div className="w-2 h-2 bg-white rounded-full" />
          </div>
        </div>

        <h2 className="text-2xl font-black mt-4">
          {user?.name || "User"}
        </h2>
        <p className="text-sm font-bold uppercase tracking-widest mt-1 text-gray-400">
          {user?.membership || "Nest Premium"}
        </p>
      </div>

      {/* Menu Items */}
      <div className="space-y-3">
        {menuItems.map((item, idx) => (
          <button
            key={idx}
            onClick={item.action}
            className={`w-full flex items-center justify-between p-4 rounded-2xl border transition-all group ${darkMode ? "bg-gray-800 border-gray-700 hover:bg-gray-700" : "bg-white border-gray-50 active:bg-gray-50"}`}
          >
            <div className="flex items-center gap-4">
              <div
                className={`w-11 h-11 rounded-xl flex items-center justify-center ${item.color}`}
              >
                <item.icon className="w-5 h-5" />
              </div>
              <span className="font-bold">
                {item.label}
              </span>
            </div>
            <ChevronRight className="w-5 h-5 text-gray-300 group-hover:translate-x-1 transition-transform" />
          </button>
        ))}

        {/* Sign Out */}
        <button
          onClick={onLogout}
          className={`w-full flex items-center justify-between p-4 mt-6 rounded-2xl border font-black transition-all ${
            darkMode
              ? "bg-red-700 border-red-700 text-red-100 hover:bg-red-600"
              : "bg-red-50/50 border-red-50 text-red-500 active:bg-red-50"
          }`}
        >
          <div className="flex items-center gap-4">
            <div className="w-11 h-11 rounded-xl flex items-center justify-center bg-red-100">
              <LogOut className="w-5 h-5" />
            </div>
            <span>Sign Out</span>
          </div>
        </button>
      </div>
    </div>
  );
}
